  ('heelevel3-444ca548-moex-00047', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'essay', 'A長照機構與 B直轄市政府衛生局（下稱 B衛生局）簽有「B直轄市特
約長期照顧家庭照顧者喘息服務行政契約書」（下稱行政契約），提供相
關喘息服務，行政契約中有 A長照機構依行政程序法第 148條自願接受
執行之約定。B衛生局發現 A長照機構有虛報費用之情事，依行政契約
之約定可處虛報費用金額 10 倍之違約金，合計新臺幣 50 萬元。B衛生
局遂限期通知甲繳納，催繳函並有「若逾期不履行，本局依法移送行政
執行分署強制執行」之記載。假設A長照機構甲逾期仍未繳還公費，B衛
生局得否以催繳函為執行名義移送該管行政執行分署強制執行？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00048', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '關於依法行政之敘述，下列何者錯誤？', '["執行法律之細節性、技術性次要事項，由行政機關發布命令為必要之規範，不違反法律保留原則", "法律優位原則又稱為消極的依法行政原則", "給付行政措施，只要預算允許，即無須適用法律保留原則", "對於人民違反行政法上義務之裁罰，其處罰之構成要件，應以法律或法律明確授權之命令定之 31750"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00049', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '依司法院大法官解釋意旨，關於信賴保護原則所需衡酌之事項，不包括下列何者？', '["法秩序變動所追求之政策目的", "國家財政負擔之能力", "修法過程中可決票數之多寡", "值得保護之信賴利益的輕重"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00050', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '依司法實務見解，下列事件所涉之爭議，何者應由普通法院審判？', '["對大學教師所為教師升等不通過", "大學生必修科目成績不及格，以致於無法如期畢業", "依據國有林地濫墾地補辦清理作業要點申請訂立租地契約未受准許", "退役軍職人員與臺灣銀行訂立優惠存款契約所生之給付利息爭議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00051', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '關於地方自治，下列敘述何者正確？', '["基於地方自治，中央不得要求地方分擔全民健保保險費之補助", "關於自治事項，地方不得以自治法規另定較中央法規更高之限制標準", "地方自治條例與中央法規牴觸者，中央主管機關應起訴請求行政法院判決自治條例無效", "地方自治團體應作為而不作為而危害公益，中央機關於情形急迫時得代行處理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00052', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '下列何者非屬公法人？', '["新竹縣五峰鄉", "新北市新店區", "國家運動訓練中心", "國家表演藝術中心"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00053', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '關於行政管轄權之敘述，下列何者正確？', '["同一事件二機關依法皆有管轄權，由受理在後之機關處理對人民較為便捷時，應由受理在後之 機關管轄", "原行政機關因組織法規變更，合併至他機關時，有關機關管轄事務變更之公告，應由原行政機 關辦理公告", "二行政機關發生管轄權爭議時，該爭議應由共同上級機關之上級機關決定之", "行政機關將其權限之一部分，委託民間團體辦理，應將其委託事項公告，並刊登政府公報或新 聞紙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00054', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '依現行法令規定，關於公務人員之任用，下列敘述何者正確？', '["曾服公務有貪污行為，經緩刑判決確定，不得任用為公務人員", "現任公務人員因犯偽造文書罪，經有罪判決並已執行完畢，不得再任公務人員", "初任各官等之試用人員，基於業務需要，經指名商調，得於試用期間調任其他職系職務", "公務人員得經依法銓敘合格而取得任用資格"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00055', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '關於公務員之懲戒與懲處，下列敘述何者錯誤？', '["得為公務員之懲戒者，係懲戒法院", "得為公務員之懲處者，係公務員服務之機關", "薦任第九職等或相當九職等以下之公務員，關於其懲戒，行政首長或其主管機關首長得逕送懲 戒法院審理", "懲戒法庭就移送之懲戒案件，不得對被付懲戒人先行裁定停止職務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00056', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '公務人員甲因執行公務屢有違失，年終獲乙等之考績評定，如甲欲提起行政救濟，下列敘述何者 正確？', '["甲不得對乙等考績評定提起任何救濟", "甲可依申訴、再申訴程序尋求救濟；針對再申訴決定，無法向行政法院提起行政訴訟", "甲可依申訴、再申訴程序尋求救濟；針對再申訴決定，可向行政法院提起行政訴訟", "甲可依復審程序尋求救濟；如對復審決定不服，可向行政法院提起行政訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL)
